import React, { useEffect } from 'react';
import { Routes, Route } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import axios from 'axios';

import Header from './components/Header';
import Footer from './components/Footer';
import HomePage from './pages/Home/HomePage';
import Login from './pages/Home/Login';
import Registration from './pages/Home/Registration';
import ForgotPassword from './pages/Home/ForgotPassword';
import AthleteDashboard from './pages/athlete/AthleteDashboard';
import AthleteTournaments from './pages/athlete/AthleteTournaments';
import AthleteHistory from './pages/athlete/AthleteHistory';
import CoachDashboard from './pages/coach/CoachDashboard';
import AdminDashboard from './pages/admin/AdminDashboard';
import JudgeDashboard from './pages/judge/JudgeDashboard';
import PrivateRoute from './components/PrivateRoute'; // Import PrivateRoute
import TournamentListScreen from './pages/tournaments/TournamentListScreen';
import TournamentDetailScreen from './pages/tournaments/TournamentDetailScreen';

import { setUser } from './store/authSlice';
import setAuthToken from './utils/setAuthToken';

// Check for token and load user
if (localStorage.token) {
    setAuthToken(localStorage.token);
}

const App = () => {
    const dispatch = useDispatch();

    useEffect(() => {
        const loadUser = async () => {
            if (localStorage.token) {
                try {
                    const res = await axios.get('/api/users/profile');
                    dispatch(setUser(res.data));
                } catch (err) {
                    console.error('Failed to load user', err);
                }
            }
        };
        loadUser();
    }, [dispatch]);

    return (
        <>
            <Header />
            <main>
                <Routes>
                    <Route path="/" element={<HomePage />} />
                    <Route path="/login" element={<Login />} />
                    <Route path="/register" element={<Registration />} />
                    <Route path="/forgot-password" element={<ForgotPassword />} />
                    <Route path="/tournaments" element={<TournamentListScreen />} />
                    <Route path="/tournaments/:id" element={<TournamentDetailScreen />} />
                    
                    {/* Secured Athlete Routes */}
                    <Route path="/athlete/dashboard" element={<PrivateRoute role="Athlete"><AthleteDashboard /></PrivateRoute>} />
                    <Route path="/athlete/tournaments" element={<PrivateRoute role="Athlete"><AthleteTournaments /></PrivateRoute>} />
                    <Route path="/athlete/history" element={<PrivateRoute role="Athlete"><AthleteHistory /></PrivateRoute>} />

                    {/* Secured Coach Route */}
                    <Route path="/coach/dashboard" element={<PrivateRoute role="Coach"><CoachDashboard /></PrivateRoute>} />

                    {/* Secured Admin Route */}
                    <Route path="/admin/dashboard" element={<PrivateRoute role="Admin"><AdminDashboard /></PrivateRoute>} />

                    {/* Secured Judge Route */}
                    <Route path="/judge/dashboard" element={<PrivateRoute role="Judge"><JudgeDashboard /></PrivateRoute>} />
                </Routes>
            </main>
            <Footer />
        </>
    );
};

export default App;
